13	export function nextGeneration(cells: Cell[]): Cell[] {
14	  const isAlive = (x: number, y: number): boolean =>
15	    cells.some(([cx, cy]) => cx === x && cy === y);
16	
17	  const countNeighbors = (x: number, y: number): number =>
18	    NEIGHBOR_OFFSETS.filter(([dx, dy]) => isAlive(x + dx, y + dy)).length;
19	
20	  const candidateKeys = new Map<string, Cell>();
21	  for (const [x, y] of cells) {
22	    for (const [dx, dy] of [[0, 0], ...NEIGHBOR_OFFSETS]) {
23	      const cell: Cell = [x + dx, y + dy];
24	      candidateKeys.set(`${cell[0]},${cell[1]}`, cell);
25	    }
26	  }
27	
28	  return [...candidateKeys.values()].filter(([x, y]) => {
29	    const neighbors = countNeighbors(x, y);
30	    if (isAlive(x, y)) {
31	      return (
32	        neighbors >= MIN_NEIGHBORS_TO_SURVIVE &&
33	        neighbors <= MAX_NEIGHBORS_TO_SURVIVE
34	      );
35	    }
36	    return neighbors === NEIGHBORS_TO_REPRODUCE;
37	  });
38	}
